+/** Metrics configuration and control. */
+
+function parseMetricsEnabled(raw: string | undefined): boolean {
+  if (!raw) return true;
+  const v = raw.toLowerCase();
+  return v !== 'false' && v !== '0' && v !== 'off';
+}
+
+function parseSampleRate(raw: string | undefined): number {
+  if (!raw) return 1.0;
+  const n = parseFloat(raw);
+  if (isNaN(n) || n < 0 || n > 1) return 1.0;
+  return n;
+}
+
+export function metricsEnabled(): boolean {
+  return parseMetricsEnabled(process.env.METRICS_ENABLED);
+}
+
+export function sampleRate(): number {
+  return parseSampleRate(process.env.SAMPLE_RATE);
+}

