@@ -0,0 +1,42 @@
+/**
+ * Metrics configuration and control.
+ */
+
+interface MetricsConfig {
+  enabled: boolean;
+  sampleRate: number;
+}
+
+const schema = {
+  enabled: (raw: string | undefined): boolean => {
+    if (!raw) return true;
+    return raw !== 'false' && raw !== '0' && raw !== 'off';
+  },
+  sampleRate: (raw: string | undefined): number => {
+    if (!raw) return 1.0;
+    const rate = parseFloat(raw);
+    if (isNaN(rate) || rate < 0 || rate > 1) {
+      throw new Error(`invalid sample rate: ${raw}, must be 0-1`);
+    }
+    return rate;
+  },
+};
+
+let cache: MetricsConfig | null = null;
+
+function load(): MetricsConfig {
+  if (cache) return cache;
+  cache = {
+    enabled: schema.enabled(process.env.METRICS_ENABLED),
+    sampleRate: schema.sampleRate(process.env.METRICS_SAMPLE_RATE),
+  };
+  return cache;
+}
+
+export function metricsEnabled(): boolean {
+  return load().enabled;
+}
+
+export function sampleRate(): number {
+  return load().sampleRate;
+}

