 /**
  * In-memory cache with a per-entry TTL. Values expire lazily on read, and the
  * cache clears itself when it sees a 'config-reloaded' event on the bus.
+ * Expired entries are actively evicted on a background interval.
  */

 import { on } from './bus.js';
@@ -34,4 +35,16 @@ export function invalidate(key: string): void {
   store.delete(key);
 }

+function evictExpired(): void {
+  const now = Date.now();
+  for (const [key, entry] of store.entries()) {
+    if (now > entry.expiresAt) {
+      store.delete(key);
+    }
+  }
+}
+
+const evictionInterval = setInterval(evictExpired, 60_000);
+evictionInterval.unref?.();
